[
  {
    "text": "The transmission window width decrease with increasing bath temperature is due to a pure dephasing channel from coupling to a bath of two-level fluctuators, and therefore the narrowing saturates when the thermal energy exceeds the characteristic energy splitting of the fluctuators, not the mode splitting.",
    "topic": "Pure dephasing from two-level fluctuators"
  },
  {
    "text": "The optimal bath bandwidth shift induced by a Duffing anharmonicity becomes detectable when the anharmonic energy scale exceeds the thermal energy, so at 1% harmonic frequency anharmonicity, the bandwidth shift is negligible only when the bath temperature is above 1% of the harmonic frequency in energy units.",
    "topic": "Anharmonicity-temperature energy scale competition"
  }
]
